<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Snake</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    background: #0d0d0d;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    gap: 20px;
  }

  h1 {
    font-size: 2rem;
    letter-spacing: 0.2em;
    color: #4ade80;
    text-shadow: 0 0 20px #4ade8066;
  }

  #score-container {
    font-size: 1.2rem;
    color: #a0a0a0;
    letter-spacing: 0.05em;
  }

  #score {
    color: #4ade80;
    font-weight: bold;
    font-size: 1.5rem;
  }

  #snake {
    display: block;
    border: 2px solid #2a2a2a;
    border-radius: 4px;
    background: #111;
    box-shadow: 0 0 40px #4ade8022, 0 0 80px #00000080;
  }

  #controls {
    display: flex;
    gap: 12px;
  }

  button {
    padding: 10px 28px;
    border: 1px solid #333;
    border-radius: 6px;
    background: #1a1a1a;
    color: #e0e0e0;
    font-size: 0.95rem;
    letter-spacing: 0.05em;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s, color 0.15s;
  }

  button:hover {
    background: #252525;
    border-color: #4ade80;
    color: #4ade80;
  }

  button:active {
    background: #1e3a2a;
  }

  #start { border-color: #4ade8066; color: #4ade80; }
  #pause { border-color: #facc1566; color: #facc15; }
  #reset { border-color: #f8717166; color: #f87171; }

  #status {
    font-size: 0.9rem;
    color: #666;
    height: 1.2em;
    letter-spacing: 0.05em;
  }

  #status.game-over { color: #f87171; }
</style>
</head>
<body>
<h1>SNAKE</h1>
<div id="score-container">SCORE: <span id="score">0</span></div>
<canvas id="snake" width="420" height="420"></canvas>
<div id="controls">
  <button id="start">START</button>
  <button id="pause">PAUSE</button>
  <button id="reset">RESET</button>
</div>
<div id="status">Press START to play</div>

<script>
(function() {
  const canvas = document.getElementById('snake');
  const ctx = canvas.getContext('2d');
  const scoreEl = document.getElementById('score');
  const statusEl = document.getElementById('status');

  const COLS = 21;
  const ROWS = 21;
  const CELL = canvas.width / COLS;

  let snakeBody, dir, nextDir, foodPos, _score, _alive, loopId;

  // Colors
  const COLOR_BG = '#111111';
  const COLOR_GRID = '#161616';
  const COLOR_FOOD = '#f87171';
  const COLOR_HEAD = '#4ade80';
  const COLOR_BODY_START = '#22c55e';
  const COLOR_BODY_END = '#14532d';
  const COLOR_EYE = '#0d0d0d';

  function initState() {
    const midX = Math.floor(COLS / 2);
    const midY = Math.floor(ROWS / 2);
    snakeBody = [
      [midX, midY],
      [midX - 1, midY],
      [midX - 2, midY],
    ];
    dir = 'right';
    nextDir = 'right';
    _score = 0;
    _alive = true;
    placeFood();
    scoreEl.textContent = '0';
    statusEl.textContent = 'Press START to play';
    statusEl.className = '';
  }

  function placeFood() {
    const occupied = new Set(snakeBody.map(([x, y]) => `${x},${y}`));
    const free = [];
    for (let x = 0; x < COLS; x++)
      for (let y = 0; y < ROWS; y++)
        if (!occupied.has(`${x},${y}`)) free.push([x, y]);
    if (free.length === 0) return;
    foodPos = free[Math.floor(Math.random() * free.length)];
  }

  function step() {
    if (!_alive) return;

    dir = nextDir;
    const [hx, hy] = snakeBody[0];
    let nx = hx, ny = hy;
    if (dir === 'up')    ny--;
    if (dir === 'down')  ny++;
    if (dir === 'left')  nx--;
    if (dir === 'right') nx++;

    // Wall collision
    if (nx < 0 || nx >= COLS || ny < 0 || ny >= ROWS) {
      _alive = false;
      statusEl.textContent = 'GAME OVER';
      statusEl.className = 'game-over';
      stopLoop();
      draw();
      return;
    }

    // Self collision (exclude tail since it moves away)
    const bodyWithoutTail = snakeBody.slice(0, snakeBody.length - 1);
    for (const [bx, by] of bodyWithoutTail) {
      if (nx === bx && ny === by) {
        _alive = false;
        statusEl.textContent = 'GAME OVER';
        statusEl.className = 'game-over';
        stopLoop();
        draw();
        return;
      }
    }

    const ate = (nx === foodPos[0] && ny === foodPos[1]);
    snakeBody.unshift([nx, ny]);
    if (ate) {
      _score++;
      scoreEl.textContent = _score;
      placeFood();
    } else {
      snakeBody.pop();
    }

    draw();
  }

  function draw() {
    const W = canvas.width;
    const H = canvas.height;

    // Background
    ctx.fillStyle = COLOR_BG;
    ctx.fillRect(0, 0, W, H);

    // Grid
    ctx.strokeStyle = COLOR_GRID;
    ctx.lineWidth = 0.5;
    for (let x = 0; x <= COLS; x++) {
      ctx.beginPath();
      ctx.moveTo(x * CELL, 0);
      ctx.lineTo(x * CELL, H);
      ctx.stroke();
    }
    for (let y = 0; y <= ROWS; y++) {
      ctx.beginPath();
      ctx.moveTo(0, y * CELL);
      ctx.lineTo(W, y * CELL);
      ctx.stroke();
    }

    // Food
    const [fx, fy] = foodPos;
    const fc = CELL * 0.35;
    const fcx = fx * CELL + CELL / 2;
    const fcy = fy * CELL + CELL / 2;
    ctx.shadowColor = '#f87171';
    ctx.shadowBlur = 12;
    ctx.fillStyle = COLOR_FOOD;
    ctx.beginPath();
    ctx.arc(fcx, fcy, fc, 0, Math.PI * 2);
    ctx.fill();
    ctx.shadowBlur = 0;

    // Snake body (tail to head so head draws on top)
    const len = snakeBody.length;
    for (let i = len - 1; i >= 0; i--) {
      const [sx, sy] = snakeBody[i];
      const t = i === 0 ? 0 : i / (len - 1);
      // Interpolate color from head to tail
      const r1 = 0x22, g1 = 0xc5, b1 = 0x5e;
      const r2 = 0x14, g2 = 0x53, b2 = 0x2d;
      const r = Math.round(r1 + (r2 - r1) * t);
      const g = Math.round(g1 + (g2 - g1) * t);
      const b = Math.round(b1 + (b2 - b1) * t);
      const color = i === 0 ? COLOR_HEAD : `rgb(${r},${g},${b})`;

      const pad = i === 0 ? 1 : 2;
      const radius = 3;
      const rx = sx * CELL + pad;
      const ry = sy * CELL + pad;
      const rw = CELL - pad * 2;
      const rh = CELL - pad * 2;

      if (i === 0) {
        ctx.shadowColor = '#4ade80';
        ctx.shadowBlur = 8;
      }
      ctx.fillStyle = color;
      ctx.beginPath();
      ctx.roundRect(rx, ry, rw, rh, radius);
      ctx.fill();
      ctx.shadowBlur = 0;

      // Eyes on head
      if (i === 0) {
        ctx.fillStyle = COLOR_EYE;
        const eyeR = CELL * 0.1;
        let e1x, e1y, e2x, e2y;
        const cx = sx * CELL + CELL / 2;
        const cy = sy * CELL + CELL / 2;
        const eo = CELL * 0.2;
        if (dir === 'right') { e1x = cx + eo; e1y = cy - eo; e2x = cx + eo; e2y = cy + eo; }
        else if (dir === 'left')  { e1x = cx - eo; e1y = cy - eo; e2x = cx - eo; e2y = cy + eo; }
        else if (dir === 'up')    { e1x = cx - eo; e1y = cy - eo; e2x = cx + eo; e2y = cy - eo; }
        else                      { e1x = cx - eo; e1y = cy + eo; e2x = cx + eo; e2y = cy + eo; }
        ctx.beginPath(); ctx.arc(e1x, e1y, eyeR, 0, Math.PI * 2); ctx.fill();
        ctx.beginPath(); ctx.arc(e2x, e2y, eyeR, 0, Math.PI * 2); ctx.fill();
      }
    }

    // Game over overlay
    if (!_alive) {
      ctx.fillStyle = 'rgba(0,0,0,0.55)';
      ctx.fillRect(0, 0, W, H);
      ctx.fillStyle = '#f87171';
      ctx.font = `bold ${CELL * 1.6}px 'Segoe UI', system-ui, sans-serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.shadowColor = '#f87171';
      ctx.shadowBlur = 20;
      ctx.fillText('GAME OVER', W / 2, H / 2);
      ctx.shadowBlur = 0;
      ctx.fillStyle = '#a0a0a0';
      ctx.font = `${CELL * 0.7}px 'Segoe UI', system-ui, sans-serif`;
      ctx.fillText(`Score: ${_score}`, W / 2, H / 2 + CELL * 1.8);
    }
  }

  let interval = 150;
  function startLoop() {
    if (!_alive) return;
    stopLoop();
    loopId = setInterval(() => step(), interval);
    statusEl.textContent = 'Playing…';
    statusEl.className = '';
  }

  function stopLoop() {
    if (loopId) { clearInterval(loopId); loopId = null; }
  }

  // Buttons
  document.getElementById('start').addEventListener('click', () => {
    if (!_alive) { initState(); draw(); }
    startLoop();
  });

  document.getElementById('pause').addEventListener('click', () => {
    if (loopId) {
      stopLoop();
      statusEl.textContent = 'Paused';
    } else if (_alive) {
      startLoop();
    }
  });

  document.getElementById('reset').addEventListener('click', () => {
    stopLoop();
    initState();
    draw();
  });

  // Keyboard
  const KEY_MAP = {
    ArrowUp: 'up', ArrowDown: 'down', ArrowLeft: 'left', ArrowRight: 'right',
    w: 'up', s: 'down', a: 'left', d: 'right',
    W: 'up', S: 'down', A: 'left', D: 'right',
  };
  const OPPOSITE = { up: 'down', down: 'up', left: 'right', right: 'left' };

  document.addEventListener('keydown', (e) => {
    const mapped = KEY_MAP[e.key];
    if (mapped) {
      e.preventDefault();
      window.game.setDir(mapped);
    }
  });

  // Public API
  window.game = {
    get w() { return COLS; },
    get h() { return ROWS; },

    reset() {
      stopLoop();
      initState();
      draw();
    },

    tick() {
      step();
    },

    setDir(d) {
      if (['up','down','left','right'].includes(d)) {
        if (OPPOSITE[d] !== dir) nextDir = d;
      }
    },

    setFood(x, y) {
      foodPos = [x, y];
      draw();
    },

    snake() {
      return snakeBody.map(([x, y]) => [x, y]);
    },

    food() {
      return [foodPos[0], foodPos[1]];
    },

    alive() {
      return _alive;
    },

    score() {
      return _score;
    },
  };

  // Init
  initState();
  draw();
})();
</script>
</body>
</html>
